import random

def simulate(p_a, p_b, trials):
    count_a = count_b = count_both = 0
    for _ in range(trials):
        a = random.random() < p_a
        b = random.random() < p_b
        if a: count_a +=1
        if b: count_b +=1
        if a and b: count_both +=1
    return count_both/trials - (count_a/trials)*(count_b/trials)
